SELECT "contacts"."id", "contacts"."categories", "contacts"."organization_id", "contacts"."first_name", "contacts"."middle_name", "contacts"."last_name", (COALESCE(COALESCE(TO_CHAR((("contacts"."created_date"::TIMESTAMP + "contacts"."created_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila')::DATE, 'mm/dd/YYYY'), ''), '') || ' ' || COALESCE(((("contacts"."created_date"::TIMESTAMP + "contacts"."created_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila'))::time::text, '')) AS created_date_time, (COALESCE(COALESCE(TO_CHAR((("contacts"."updated_date"::TIMESTAMP + "contacts"."updated_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila')::DATE, 'mm/dd/YYYY'), ''), '') || ' ' || COALESCE(((("contacts"."updated_date"::TIMESTAMP + "contacts"."updated_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila'))::time::text, '')) AS updated_date_time, "contacts"."code", "contacts"."categories", "contacts"."organization_id", "contacts"."first_name", "contacts"."middle_name", "contacts"."last_name", "contacts"."status", COALESCE(TO_CHAR((("contacts"."created_date"::TIMESTAMP + "contacts"."created_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila')::DATE, 'mm/dd/YYYY'), '') AS "created_date", ((("contacts"."created_date"::TIMESTAMP + "contacts"."created_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila'))::time::text AS created_time, COALESCE(TO_CHAR((("contacts"."updated_date"::TIMESTAMP + "contacts"."updated_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila')::DATE, 'mm/dd/YYYY'), '') AS "updated_date", ((("contacts"."updated_date"::TIMESTAMP + "contacts"."updated_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila'))::time::text AS updated_time, COALESCE( ( SELECT JSONB_AGG(elem ) FROM (SELECT JSONB_BUILD_OBJECT('email', "contact_emails"."email", 'is_primary', "contact_emails"."is_primary") AS elem FROM contact_emails contact_emails WHERE (contact_emails.tombstone = 0) AND "contacts"."id" = "contact_emails"."contact_id") sub ), '[]' ) AS contact_emails, COALESCE( ( SELECT JSONB_AGG(elem ) FROM (SELECT JSONB_BUILD_OBJECT('phone_number_raw', "contact_phone_numbers"."phone_number_raw") AS elem FROM contact_phone_numbers contact_phone_numbers WHERE (contact_phone_numbers.tombstone = 0) AND "contacts"."id" = "contact_phone_numbers"."contact_id") sub ), '[]' ) AS contact_phone_numbers, COALESCE( ( SELECT JSONB_AGG(elem ) FROM (SELECT JSONB_BUILD_OBJECT('id', "created_by_account_organizations"."id", 'contact_id', "created_by_account_organizations"."contact_id") AS elem FROM account_organizations created_by_account_organizations WHERE (created_by_account_organizations.tombstone = 0) AND "contacts"."created_by" = "created_by_account_organizations"."id") sub ), '[]' ) AS created_by_account_organizations, COALESCE( ( SELECT JSONB_AGG(elem ) FROM (SELECT JSONB_BUILD_OBJECT('id', "created_by"."id", 'first_name', "created_by"."first_name", 'last_name', "created_by"."last_name", 'full_name', (COALESCE("created_by"."first_name", '') || ' ' || COALESCE("created_by"."last_name", ''))) AS elem FROM contacts created_by WHERE (created_by.tombstone = 0) AND "created_by_account_organizations"."contact_id" = "created_by"."id") sub ), '[]' ) AS created_by, COALESCE( ( SELECT JSONB_AGG(elem ) FROM (SELECT JSONB_BUILD_OBJECT('id', "updated_by_account_organizations"."id", 'contact_id', "updated_by_account_organizations"."contact_id") AS elem FROM account_organizations updated_by_account_organizations WHERE (updated_by_account_organizations.tombstone = 0) AND "contacts"."updated_by" = "updated_by_account_organizations"."id") sub ), '[]' ) AS updated_by_account_organizations, COALESCE( ( SELECT JSONB_AGG(elem ) FROM (SELECT JSONB_BUILD_OBJECT('id', "updated_by"."id", 'first_name', "updated_by"."first_name", 'last_name', "updated_by"."last_name", 'full_name', (COALESCE("updated_by"."first_name", '') || ' ' || COALESCE("updated_by"."last_name", ''))) AS elem FROM contacts updated_by WHERE (updated_by.tombstone = 0) AND "updated_by_account_organizations"."contact_id" = "updated_by"."id") sub ), '[]' ) AS updated_by FROM contacts LEFT JOIN LATERAL (SELECT "joined_contact_emails"."email", "joined_contact_emails"."is_primary" FROM "contact_emails" "joined_contact_emails" WHERE (joined_contact_emails.tombstone = 0) AND "joined_contact_emails"."contact_id" = "contacts"."id" ) AS "contact_emails" ON TRUE LEFT JOIN LATERAL (SELECT "joined_contact_phone_numbers"."phone_number_raw" FROM "contact_phone_numbers" "joined_contact_phone_numbers" WHERE (joined_contact_phone_numbers.tombstone = 0) AND "joined_contact_phone_numbers"."contact_id" = "contacts"."id" ) AS "contact_phone_numbers" ON TRUE LEFT JOIN LATERAL (SELECT "joined_created_by_account_organizations"."id", "joined_created_by_account_organizations"."contact_id" FROM "account_organizations" "joined_created_by_account_organizations" WHERE (joined_created_by_account_organizations.tombstone = 0) AND "joined_created_by_account_organizations"."id" = "contacts"."created_by" ) AS "created_by_account_organizations" ON TRUE LEFT JOIN LATERAL (SELECT "joined_created_by"."id", "joined_created_by"."first_name", "joined_created_by"."last_name" FROM "contacts" "joined_created_by" WHERE (joined_created_by.tombstone = 0) AND "joined_created_by"."id" = "created_by_account_organizations"."contact_id" ) AS "created_by" ON TRUE LEFT JOIN LATERAL (SELECT "joined_updated_by_account_organizations"."id", "joined_updated_by_account_organizations"."contact_id" FROM "account_organizations" "joined_updated_by_account_organizations" WHERE (joined_updated_by_account_organizations.tombstone = 0) AND "joined_updated_by_account_organizations"."id" = "contacts"."updated_by" ) AS "updated_by_account_organizations" ON TRUE LEFT JOIN LATERAL (SELECT "joined_updated_by"."id", "joined_updated_by"."first_name", "joined_updated_by"."last_name" FROM "contacts" "joined_updated_by" WHERE (joined_updated_by.tombstone = 0) AND "joined_updated_by"."id" = "updated_by_account_organizations"."contact_id" ) AS "updated_by" ON TRUE WHERE (contacts.tombstone = 0) AND (COALESCE(COALESCE(TO_CHAR((("contacts"."created_date"::TIMESTAMP + "contacts"."created_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila')::DATE, 'mm/dd/YYYY'), ''), '') || ' ' || COALESCE(((("contacts"."created_date"::TIMESTAMP + "contacts"."created_time"::INTERVAL) AT TIME ZONE 'UTC' AT TIME ZONE 'Asia/Manila'))::time::text, ''))::text LIKE '%08/15/2025 15%%' AND contacts.status::text IN ('Active', 'Draft') ORDER BY LOWER("contacts"."status") ASC LIMIT 100